  ('police-8b7f1efc-moex-00631', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '關於告訴乃論之罪之「告訴」，依據刑事訴訟法之規定，下列敘述何者正確？', '["告訴人提出告訴時，應向受理告訴之司法警察官，指明所欲告訴之罪名，其告訴方屬適法", "6個月之告訴期間，自犯罪行為發生時之翌日起算", "被害人已死亡，其生前曾明確表示不欲提出告訴時，被害人之配偶不受被害人生前不欲提出告 訴之意思拘束，仍得獨立提出告訴", "告訴人向受理告訴之司法警察官明確表示，僅欲對共犯中之某一特定共犯提出告訴，其所提告 訴之效力，仍及於全部共犯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00632', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '路人甲於司法警察官乙、丙、丁依法執行路檢勤務時，當場辱罵乙、丙、丁為蠢蛋、米蟲、走狗。 乙、丙、丁因而以甲為侮辱公務員罪之現行犯加以逮捕。嗣經甲與多位地方賢達之求情，乙、丙、 丁亦認甲之犯行確屬輕微且頗有悔意，於製作完成警詢筆錄與完備證據保全程序後，欲讓甲離去。 依據刑事訴訟法之規定，下列敘述何者正確？', '["得令甲自行離去，案件之卷證以函送方式移請檢察官處理", "不得令甲自行離去，案件之卷證與甲應一律以解送方式移請檢察官處理", "得經檢察官之許可，令甲自行離去，不予解送，案件之卷證以函送方式移請檢察官處理", "得經檢察官之許可，案件之卷證以解送方式、甲以函送方式移請檢察官處理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00633', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察官甲爲緝捕販毒之慣犯乙，乃偽裝成吸毒者，藉機與乙及乙長期販毒之對象丙、丁等人 熟識。嗣取得乙、丙、丁之信任後，甲向乙佯稱，欲向乙購買些許毒品自用，乙不疑有詐自其置 物櫃中取出毒品欲販售予甲。甲見機不可失，乃表明為司法警察官之身分與出示證明文件，並以 乙為販毒之現行犯加以逮捕。依據最高法院司法實務之見解，下列敘述何者正確？', '["甲係實施合法之誘捕偵查", "甲係實施合法之臥底偵查", "甲係實施不合法之控制下交付", "甲係實施不合法之隱藏身分偵查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00634', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '刑事訴訟法第156條第2項規定：「被告或共犯之自白，不得作為有罪判決之唯一證據。」關於本 項規定，下列敘述何者正確？', '["係屬有關證據價值之規範", "係屬有關證據能力之規範", "係屬有關證據方法之規範", "係屬有關證據調查程序之規範"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00635', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '關於證據法則，依據刑事訴訟法之規定，下列敘述何者正確？', '["原則上證據能力之判斷，由法院依自由心證主義判斷之", "原則上證據證明力之判斷，由法院依證據排除法則判斷之", "原則上證物之證據調查程序，應提示予當事人、辯護人等辨認之", "原則上證據方法之判斷，由法院依當事人進行主義判斷之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00636', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '甲、乙、丙三人共犯殺人罪，嗣為司法警察機關同時依被告身分將三人依法拘提到案。於警詢程 序中，甲自承殺人罪，並謂乙、丙亦同時全程參與共犯該起殺人罪。乙於警詢中供稱，殺人罪係 由甲、丙二人所為，渠並未參與該起殺人罪。丙於警詢中則供稱，該起殺人罪係由渠與甲二人所 為，乙僅係在場目擊殺人之案發經過，並未參與該起殺人罪。依據刑事訴訟法之規定，下列敘述 何者正確？', '["乙之警詢供述，對甲、丙而言，係屬傳聞證據", "甲、乙、丙之警詢供述，均屬傳聞證據", "甲之警詢供述，可作為乙犯罪之補強證據", "丙之警詢供述，可作為甲犯罪之補強證據"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
